const express = require('express');
const router = express.Router();

// Middleware to check if user is an administrator
const requireAdmin = (req, res, next) => {
  if (!req.user) {
    return res.status(401).json({ error: 'Authentication required' });
  }
  
  if (req.user.role !== 'admin' && req.user.role !== 'administrator') {
    return res.status(403).json({ error: 'Access denied. Administrator privileges required.' });
  }
  
  next();
};

// GET /api/admin/users - Returns all users (admin only)
router.get('/api/admin/users', requireAdmin, async (req, res) => {
  try {
    // Assuming you have a User model/database connection
    // Replace this with your actual database query
    const db = req.app.get('db'); // or however you access your database
    
    // Fetch all users from database
    const users = await db.query('SELECT id, username, email, role, created_at, updated_at, status FROM users ORDER BY created_at DESC');
    
    // Alternatively, if using an ORM like Sequelize or Mongoose:
    // const User = require('../models/User');
    // const users = await User.findAll({
    //   attributes: ['id', 'username', 'email', 'role', 'created_at', 'updated_at', 'status']
    // });
    
    // Filter sensitive fields before sending response
    const sanitizedUsers = users.map(user => ({
      id: user.id,
      username: user.username,
      email: user.email,
      role: user.role,
      status: user.status,
      createdAt: user.created_at || user.createdAt,
      updatedAt: user.updated_at || user.updatedAt
    }));
    
    res.json({
      success: true,
      count: sanitizedUsers.length,
      users: sanitizedUsers
    });
    
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

module.exports = router;